for (const item of $input.all()) {

  let userURL = String(item.json.userURL || "").trim();
  let competitorURL = String(item.json.competitorURL || "").trim();
  let email = String(item.json.userEmail || "").trim();

  function isValidURL(url) {
    return url.startsWith("http") && url.includes(".");
  }

  function isValidEmail(email) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }

  item.json.isValid =
    isValidURL(userURL) &&
    isValidURL(competitorURL) &&
    isValidEmail(email);

  // ✅ FINAL STATUS UPDATE
  item.json.jobId = item.json.jobId.toString().trim(); // space remove
  item.json.step = 5;
  item.json.status = "done";


}

