const output = [];

for (const item of $input.all()) {

  let html = item.json.data || "";

  // ❌ Remove script/style पहले ही
  html = html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '');

  // ✅ CLEAN FUNCTION
  const clean = (t) =>
    (t || "")
      .replace(/<[^>]*>/g, " ")
      .replace(/\s+/g, " ")
      .trim();

  // ✅ TITLE
  const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);

  // ✅ H1
  const h1Match = html.match(/<h1[^>]*>(.*?)<\/h1>/i);

  // ✅ META DESCRIPTION (multiple handle)
  const metaMatches = [...html.matchAll(/<meta\s+name="description"\s+content="([^"]*)"/gi)];
  const meta = metaMatches.length > 0
    ? metaMatches[metaMatches.length - 1][1]
    : "";

  // 🔥🔥🔥 REAL BODY EXTRACTION (MAIN FIX)
  let bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  let bodyHTML = bodyMatch ? bodyMatch[1] : html;

  // ❌ Remove unwanted sections
  bodyHTML = bodyHTML
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<noscript[^>]*>[\s\S]*?<\/noscript>/gi, '')
    .replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '');

  // ❌ Remove JSON schema + JS junk
  bodyHTML = bodyHTML
    .replace(/\{[\s\S]*?\}/g, ' ')
    .replace(/window\.[\s\S]*?;/g, ' ')
    .replace(/!function\([\s\S]*?\}/g, ' ');

  // ✅ FINAL CLEAN BODY TEXT
  const bodyText = bodyHTML
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 1200);

  output.push({
    json: {
      url: item.json.url || item.json.userURL || "",
      siteType: item.json.siteType || "unknown",
      userEmail: item.json.userEmail || "",
      userURL: item.json.userURL || "",
      competitorURL: item.json.competitorURL || "",

      title: clean(titleMatch?.[1] || ""),
      h1: clean(h1Match?.[1] || titleMatch?.[1] || ""),
      metaDescription: clean(meta),
      bodyText: bodyText
    }
  });
}

return output;

